#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use CGI::Carp qw(fatalsToBrowser);

my $log_dir = '/path/to/logs'; # Change to your log directory

print header('text/html');
print start_html('Log Viewer');

my $filename = param('logfile');

if ($filename) {
    my $file_path = "$log_dir/$filename";

    if (-e $file_path && -r $file_path) {
        print h2("Displaying log file: $filename");
        open(my $fh, '<', $file_path) or die "Cannot open file: $!";
        
        while (my $line = <$fh>) {
            print p(escapeHTML($line));
        }

        close($fh);
    } else {
        print p("Error: File does not exist or is not readable.");
    }
} else {
    print p("Error: No log file specified.");
}

print end_html;